#define ETA 0.3f
#define MOMENTUM 0.3f
#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16

__kernel void bpnn_layerforward_ocl(
    __global float *input,
    __global float *output,
    __global float *weights,
    __global float *partial_sum,
    __local float *local_mem1,
    __local float *local_mem2,
    cl_int in,
    cl_int hid
) {
    cl_int j = get_global_id(1) + 1;
    cl_int k_block = get_global_id(0);

    if (j <= hid && k_block <= in / BLOCK_SIZE) {
        float sum = 0.0f;

        cl_int start_k = k_block * BLOCK_SIZE;
        cl_int end_k = start_k + BLOCK_SIZE;
        if (end_k > in) end_k = in + 1;

        for (cl_int k = start_k; k < end_k; k++) {
            sum += weights[k * (hid + 1) + j] * input[k];
        }

        partial_sum[k_block * hid + (j - 1)] = sum;
    }
}

__kernel void bpnn_adjust_weights_ocl(
    __global float *delta,
    cl_int hid,
    __global float *input,
    cl_int in,
    __global float *weights,
    __global float *old_weights
) {
    cl_int j = get_global_id(1) + 1;
    cl_int k = get_global_id(0);

    if (j <= hid && k <= in) {
        float new_dw = (ETA * delta[j] * input[k]) + (MOMENTUM * old_weights[k * (hid + 1) + j]);
        weights[k * (hid + 1) + j] += new_dw;
        old_weights[k * (hid + 1) + j] = new_dw;
    }
}
